function addLiquidity(
    address tokenA,
    address tokenB,
    uint amountADesired,
    uint amountBDesired,
    uint amountAMin,
    uint amountBMin,
    address to,
    uint deadline
) external virtual override ensure(deadline) returns (uint amountA, uint amountB, uint liquidity) {
    (amountA, amountB) = _addLiquidity(tokenA, tokenB, amountADesired, amountBDesired, amountAMin, amountBMin);
    address pair = PancakeLibrary.pairFor(factory, tokenA, tokenB);
    TransferHelper.safeTransferFrom(tokenA, msg.sender, pair, amountA);
    TransferHelper.safeTransferFrom(tokenB, msg.sender, pair, amountB);
    liquidity = IPancakePair(pair).mint(to);
}

function removeLiquidityETHWithPermit(
    address token,
    uint liquidity,
    uint amountTokenMin,
    uint amountETHMin,
    address to,
    uint deadline,
    bool approveMax, uint8 v, bytes32 r, bytes32 s
) external virtual override returns (uint amountToken, uint amountETH) {
    address pair = PancakeLibrary.pairFor(factory, token, WETH);
    uint value = approveMax ? uint(-1) : liquidity;
    IPancakePair(pair).permit(msg.sender, address(this), value, deadline, v, r, s);
    (amountToken, amountETH) = removeLiquidityETH(token, liquidity, amountTokenMin, amountETHMin, to, deadline);
}

function removeLiquidityETHSupportingFeeOnTransferTokens(
    address token,
    uint liquidity,
    uint amountTokenMin,
    uint amountETHMin,
    address to,
    uint deadline
) public virtual override ensure(deadline) returns (uint amountETH) {
    (, amountETH) = removeLiquidity(
        token,
        WETH,
        liquidity,
        amountTokenMin,
        amountETHMin,
        address(this),
        deadline
    );
    TransferHelper.safeTransfer(token, to, IERC20(token).balanceOf(address(this)));
    IWETH(WETH).withdraw(amountETH);
    TransferHelper.safeTransferETH(to, amountETH);
}

function removeLiquidityETHWithPermitSupportingFeeOnTransferTokens(
    address token,
    uint liquidity,
    uint amountTokenMin,
    uint amountETHMin,
    address to,
    uint deadline,
    bool approveMax, uint8 v, bytes32 r, bytes32 s
) external virtual override returns (uint amountETH) {
    address pair = PancakeLibrary.pairFor(factory, token, WETH);
    uint value = approveMax ? uint(-1) : liquidity;
    IPancakePair(pair).permit(msg.sender, address(this), value, deadline, v, r, s);
    amountETH = removeLiquidityETHSupportingFeeOnTransferTokens(
        token, liquidity, amountTokenMin, amountETHMin, to, deadline
    );
}

function proposeUpgrade(
    address proxyAddress,
    string memory newImplementationContractName,
    Options memory opts
) internal returns (ProposeUpgradeResponse memory) {
    opts.defender.useDefenderDeploy = true;
    address proxyAdminAddress = Core.getAdminAddress(proxyAddress);
    address newImplementationAddress = Core.prepareUpgrade(newImplementationContractName, opts);
    return
        DefenderDeploy.proposeUpgrade(
            proxyAddress,
            proxyAdminAddress,
            newImplementationAddress,
            newImplementationContractName,
            opts
        );
}

function isOperatorAllowed(address registrant, address operator) external view returns (bool) {
    address registration = _registrations[registrant];
    if (registration != address(0)) {
        EnumerableSet.AddressSet storage filteredOperatorsRef;
        EnumerableSet.Bytes32Set storage filteredCodeHashesRef;

        filteredOperatorsRef = _filteredOperators[registration];
        filteredCodeHashesRef = _filteredCodeHashes[registration];

        if (filteredOperatorsRef.contains(operator)) {
            revert AddressFiltered(operator);
        }
        if (operator.code.length > 0) {
            bytes32 codeHash = operator.codehash;
            if (filteredCodeHashesRef.contains(codeHash)) {
                revert CodeHashFiltered(operator, codeHash);
            }
        }
    }
    return true;
}

function calculateMinAmount(
  uint256 midPriceNumerator,
  uint256 midPriceDenominator,
  uint256 amount,
  uint256 maxSlippage // as fraction
) public pure returns (uint256) {
  FixidityLib.Fraction memory maxSlippageFraction = FixidityLib.wrap(maxSlippage);

  FixidityLib.Fraction memory price = FixidityLib.newFixedFraction(
    midPriceNumerator,
    midPriceDenominator
  );
  FixidityLib.Fraction memory amountFraction = FixidityLib.newFixed(amount);
  FixidityLib.Fraction memory totalAmount = price.multiply(amountFraction);

  return
    totalAmount
      .subtract(price.multiply(maxSlippageFraction).multiply(amountFraction))
      .fromFixed();
}

function transferFrom(address from, address to, uint256 value) external returns (bool) {
  require(to != address(0), "transfer attempted to reserved address 0x0");
  require(value <= balanceOf(from), "transfer value exceeded balance of sender");
  require(
    value <= allowed[from][msg.sender],
    "transfer value exceeded sender's allowance for spender"
  );

  bool success;
  (success, ) = TRANSFER.call.value(0).gas(gasleft())(abi.encode(from, to, value));
  require(success, "CELO transfer failed");

  allowed[from][msg.sender] = allowed[from][msg.sender].sub(value);
  emit Transfer(from, to, value);
  return true;
}

function modexp(
    bytes memory base,
    bytes memory exponent,
    bytes memory modulus
) internal view returns (bool success, bytes memory output) {
    bytes memory input = abi.encodePacked(
        uint256(base.length),
        uint256(exponent.length),
        uint256(modulus.length),
        base,
        exponent,
        modulus
    );

    output = new bytes(modulus.length);

    assembly {
        success := staticcall(
            gas(),
            5,
            add(input, 32),
            mload(input),
            add(output, 32),
            mload(modulus)
        )
    }
}

function _validateAdditionalParametersAndGetOfferedItemId(
    address collection,
    bytes calldata makerAdditionalParameters,
    bytes calldata takerAdditionalParameters
) private view returns (uint256) {
    (
        bytes32 messageId,
        bytes memory payload,
        uint256 timestamp,
        bytes memory signature,
        uint256 offeredItemId
    ) = abi.decode(takerAdditionalParameters, (bytes32, bytes, uint256, bytes, uint256));

    uint256 transferCooldownPeriod = abi.decode(makerAdditionalParameters, (uint256));

    _verifyReservoirOracle(
        collection,
        offeredItemId,
        transferCooldownPeriod,
        messageId,
        payload,
        timestamp,
        signature
    );

    return offeredItemId;
}

function transferAllowed(
    address mToken,
    address src,
    address dst,
    uint transferTokens
) external override returns (uint) {
    // Pausing is a very serious situation - we revert to sound the alarms
    require(!transferGuardianPaused, "transfer is paused");

    // Currently the only consideration is whether or not
    //  the src is allowed to redeem this many tokens
    uint allowed = redeemAllowedInternal(mToken, src, transferTokens);
    if (allowed != uint(Error.NO_ERROR)) {
        return allowed;
    }

    // Keep the flywheel moving
    updateAndDistributeSupplierRewardsForToken(mToken, src);
    updateAndDistributeSupplierRewardsForToken(mToken, dst);

    return uint(Error.NO_ERROR);
}

function setAllowedToVoteOverMaxNumberOfGroups(bool flag) public {
  address account = getAccounts().voteSignerToAccount(msg.sender);
  IValidators validators = getValidators();
  require(
    !validators.isValidator(account),
    "Validators cannot vote for more than max number of groups"
  );
  require(
    !validators.isValidatorGroup(account),
    "Validator groups cannot vote for more than max number of groups"
  );

  if (!flag) {
    require(
      votes.groupsVotedFor[account].length <= maxNumGroupsVotedFor,
      "Too many groups voted for!"
    );
  }

  allowedToVoteOverMaxNumberOfGroups[account] = flag;
  emit AllowedToVoteOverMaxNumberOfGroups(account, flag);
}

function updateParticipationBaseline(Proposals.Proposal storage proposal) private {
  FixidityLib.Fraction memory participation = proposal.getParticipation();
  FixidityLib.Fraction memory participationComponent = participation.multiply(
    participationParameters.baselineUpdateFactor
  );
  FixidityLib.Fraction memory baselineComponent = participationParameters.baseline.multiply(
    FixidityLib.fixed1().subtract(participationParameters.baselineUpdateFactor)
  );
  participationParameters.baseline = participationComponent.add(baselineComponent);
  if (participationParameters.baseline.lt(participationParameters.baselineFloor)) {
    participationParameters.baseline = participationParameters.baselineFloor;
  }
  emit ParticipationBaselineUpdated(participationParameters.baseline.unwrap());
}

function deletePayment(address paymentId) private {
  EscrowedPayment storage payment = escrowedPayments[paymentId];
  address[] storage received = receivedPaymentIds[payment.recipientIdentifier];
  address[] storage sent = sentPaymentIds[payment.sender];

  escrowedPayments[received[received.length - 1]].receivedIndex = payment.receivedIndex;
  received[payment.receivedIndex] = received[received.length - 1];
  received.length = received.length.sub(1);

  escrowedPayments[sent[sent.length - 1]].sentIndex = payment.sentIndex;
  sent[payment.sentIndex] = sent[sent.length - 1];
  sent.length = sent.length.sub(1);

  delete escrowedPayments[paymentId];
  delete trustedIssuersPerPayment[paymentId];
  emit TrustedIssuersUnset(paymentId);
}

