function _debitMsgSender(uint _amount) internal returns (uint messageFee) {
    uint msgSenderBalance = balanceOf(msg.sender);

    if (msgSenderBalance < _amount) {
        require(msgSenderBalance + msg.value >= _amount, "NativeOFTV2: Insufficient msg.value");

        // user can cover difference with additional msg.value ie. wrapping
        uint mintAmount = _amount - msgSenderBalance;
        _mint(address(msg.sender), mintAmount);

        // update the messageFee to take out mintAmount
        messageFee = msg.value - mintAmount;
    } else {
        messageFee = msg.value;
    }

    _transfer(msg.sender, address(this), _amount);
    return messageFee;
}

function getEther(
    ERC20 src,
    address destAddress,
    uint maxDestAmount,
    uint minConversionRate,
    address walletId
)
    public
{
    // Use the full balance of tokens transferred from the trade executor
    uint256 srcAmount = src.balanceOf(this);

    if (src.allowance(this, exchange) < srcAmount) {
        // Approve the exchange to transfer tokens from this contract to the reserve
        src.approve(exchange, MAX_UINT);
    }

    Kyber(exchange).trade(
        src,
        srcAmount,
        ETH_TOKEN_ADDRESS,
        destAddress,
        maxDestAmount,
        minConversionRate,
        walletId
    );
}

function beforeHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    view
    override
    onlyDefaultExecutionMode(_mode)
{
    (uint128 blockAfterThreshold_, uint128 blockBeforeThreshold_) = getTermsInfo(_terms);

    if (blockAfterThreshold_ > 0) {
        // this means there has been a after blocknumber set for which the delegation must be used
        require(block.number > blockAfterThreshold_, "BlockNumberEnforcer:early-delegation");
    }

    if (blockBeforeThreshold_ > 0) {
        // this means there has been a before blocknumber set for which the delegation must be used
        require(block.number < blockBeforeThreshold_, "BlockNumberEnforcer:expired-delegation");
    }
}

function beforeHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    view
    override
    onlyDefaultExecutionMode(_mode)
{
    (uint128 timestampAfterThreshold_, uint128 timestampBeforeThreshold_) = getTermsInfo(_terms);

    if (timestampAfterThreshold_ > 0) {
        // this means there has been a timestamp set for after which the delegation can be used
        require(block.timestamp > timestampAfterThreshold_, "TimestampEnforcer:early-delegation");
    }

    if (timestampBeforeThreshold_ > 0) {
        // this means there has been a timestamp set for before which the delegation can be used
        require(block.timestamp < timestampBeforeThreshold_, "TimestampEnforcer:expired-delegation");
    }
}

function buyNFT(ListingData calldata listingData, address paymentCurrency)
    override
    external
    checkListingData(listingData, paymentCurrency) {

        // Check balances and allowances, convert payment currency if needed, calculate royalties and transfer funds
        checkAndTransferFunds(listingData, paymentCurrency);

        // Transfer NFT to new Owner
        IERC721(contractRegistry.getContractAddress(ACCOUNT_TOKEN_HASH)).safeTransferFrom(
            listingData.tokenOwner,
            msg.sender,
            listingData.tokenId
        );

        emit NFTSold(listingData.tokenId, paymentCurrency, listingData.amount);

    }

function buyNFT(ListingData calldata listingData, address paymentCurrency, uint256 amountInMax, uint256 treasuryRoyaltiesMin)
    override
    external
    checkListingData(listingData, paymentCurrency) {

        // Check balances and allowances, convert payment currency if needed, calculate royalties and transfer funds
        checkAndTransferFunds(listingData, paymentCurrency, amountInMax, treasuryRoyaltiesMin);

        // Prevent replay attacks and reentrancy
        invalidatedListingHashes[getListingDataHash(listingData)] = true;

        // Transfer NFT to new Owner
        IERC721(contractRegistry.getContractAddress(ACCOUNT_TOKEN_HASH)).safeTransferFrom(
            listingData.tokenOwner,
            msg.sender,
            listingData.tokenId
        );

        emit NFTSold(listingData.tokenId, paymentCurrency, listingData.amount);

    }

function revokeListing(ListingData calldata listingData) override external {

    bytes32 listingHash = getListingDataHash(listingData);
    require(!invalidatedListingHashes[listingHash], "Listing already revoked");

    address seller = ECDSA.recover(listingHash, listingData.signature);
    require(seller == listingData.tokenOwner, "Bad listing request");

    require(msg.sender == seller, "Only the seller can revoke his listing");

    invalidatedListingHashes[listingHash] = true;

    emit NFTListingRevoked(listingData.tokenId, listingHash);
}

function liquidateAccount(uint256 nftId) public verifySenderAndNFT(nftId) override {

    rebaseStaking();

    IAccountToken accountTokens = IAccountToken(contractRegistry.getContractAddress(ACCOUNT_TOKEN_HASH));

    bool liquidated = accountTokens.requestLiquidation(nftId);
    if (liquidated) {

        IRewardDistributor rewardDistributor = IRewardDistributor(contractRegistry.getContractAddress(REWARD_DISTRIBUTOR_HASH));
        IStakingManager stakingManager = IStakingManager(contractRegistry.getContractAddress(STAKING_MANAGER_HASH));

        rewardDistributor.liquidateAccount(nftId);
        stakingManager.liquidateAccount(nftId, msg.sender);

        emit AccountLiquidated(nftId);
    } else {
        emit AccountLiquidationStarted(nftId);
    }
}

function _setLiquidationIncentive(
    uint newLiquidationIncentiveMantissa
) external returns (uint) {
    // Check caller is admin
    if (msg.sender != admin) {
        return
            fail(
                Error.UNAUTHORIZED,
                FailureInfo.SET_LIQUIDATION_INCENTIVE_OWNER_CHECK
            );
    }

    // Save current value for use in log
    uint oldLiquidationIncentiveMantissa = liquidationIncentiveMantissa;

    // Set liquidation incentive to new incentive
    liquidationIncentiveMantissa = newLiquidationIncentiveMantissa;

    // Emit event with old incentive, new incentive
    emit NewLiquidationIncentive(
        oldLiquidationIncentiveMantissa,
        newLiquidationIncentiveMantissa
    );

    return uint(Error.NO_ERROR);
}

