    address rateLimitedAllowance,
    address tokenAddress,
    address userAddress,
    uint256 amount
) external whenNotPaused onlyRole(EXECUTIONER_ROLE) {
    require(
        rateLimitedAllowance != address(0),
        "Invalid rate limited contract"
    );
    require(tokenAddress != address(0), "Invalid token address");
    require(userAddress != address(0), "Invalid user address");

    IRateLimitedAllowance(rateLimitedAllowance).transferFrom(
        userAddress,
        beneficiary,
        amount,
        tokenAddress
    );

    emit Withdraw(
        tokenAddress,
        userAddress,
        beneficiary,
        rateLimitedAllowance,
        amount
    );
}

function rebroadcastProposal(uint256 proposalId) external payable {
    ProposalState proposalState = state(proposalId);
    require(
        proposalState == ProposalState.Active,
        "MultichainGovernor: invalid state"
    );

    Proposal storage proposal = proposals[proposalId];

    bytes memory payload = abi.encode(
        proposalId,
        proposal.voteSnapshotTimestamp,
        proposal.votingStartTime,
        proposal.votingEndTime,
        proposal.crossChainVoteCollectionEndTimestamp
    );

    _bridgeOutAll(payload);

    emit ProposalRebroadcasted(proposalId, payload);
}

function rebroadcastProposal(uint256 proposalId) external payable {
    ProposalState proposalState = state(proposalId);
    if (proposalState != ProposalState.Active) {
        revert InvalidProposalState(proposalState, ProposalState.Active);
    }

    Proposal storage proposal = proposals[proposalId];

    bytes memory payload = abi.encode(
        proposalId,
        proposal.voteSnapshotTimestamp,
        proposal.votingStartTime,
        proposal.votingEndTime,
        proposal.crossChainVoteCollectionEndTimestamp
    );

    _bridgeOutAll(payload);

    emit ProposalRebroadcasted(proposalId, payload);
}

function getBorrowRate(
    uint cash,
    uint borrows,
    uint reserves
) public view override returns (uint) {
    uint util = utilizationRate(cash, borrows, reserves);

    if (util <= kink) {
        return
            util.mul(multiplierPerTimestamp).div(1e18).add(
                baseRatePerTimestamp
            );
    } else {
        uint normalRate = kink.mul(multiplierPerTimestamp).div(1e18).add(
            baseRatePerTimestamp
        );
        uint excessUtil = util.sub(kink);
        return
            excessUtil.mul(jumpMultiplierPerTimestamp).div(1e18).add(
                normalRate
            );
    }
}

