function delegatedFwd(address _dst, bytes _calldata) internal {
  require(isContract(_dst), "The destination address is not a contract");

  // solium-disable-next-line security/no-inline-assembly
  assembly {
    let result := delegatecall(sub(gas, 10000), _dst, add(_calldata, 0x20), mload(_calldata), 0, 0)
    let size := returndatasize

    let ptr := mload(0x40)
    returndatacopy(ptr, 0, size)

    // revert instead of invalid() bc if the underlying call failed with invalid() it already wasted gas.
    // if the call returned error data, forward it
    switch result case 0 { revert(ptr, size) }
    default { return(ptr, size) }
  }
}

function getLiquidationInfo(uint256 tokenId) public view override returns (LiquidationInfo memory info) {

    info.requestTime = liquidationRequestTimes[tokenId];
    info.availableTime = info.requestTime + liquidationGracePeriod;
    info.expirationTime = info.availableTime + liquidationClaimPeriod;

    if (info.availableTime > block.timestamp) {
        info.status = LiquidationStatus.IN_PROGRESS;
    }else if (info.expirationTime < block.timestamp) {
        info.status = LiquidationStatus.NOT_REQUESTED;
    }else {
        info.status = LiquidationStatus.AVAILABLE;
    }

    return info;
}

function canCallWithDelay(
    address authority,
    address caller,
    address target,
    bytes4 selector
) internal view returns (bool immediate, uint32 delay) {
    bytes memory data = abi.encodeCall(IAuthority.canCall, (caller, target, selector));

    assembly ("memory-safe") {
        mstore(0x00, 0x00)
        mstore(0x20, 0x00)

        if staticcall(gas(), authority, add(data, 0x20), mload(data), 0x00, 0x40) {
            immediate := mload(0x00)
            delay := mload(0x20)

            // If delay does not fit in a uint32, return 0 (no delay)
            // equivalent to: if gt(delay, 0xFFFFFFFF) { delay := 0 }
            delay := mul(delay, iszero(shr(32, delay)))
        }
    }
}

