function getUserStakingVotingPower(
    address _user
) public view virtual returns (Votes memory _result) {
    if (address(safetyModule) != address(0)) {
        // stkWELL snapshots (ERC20WithSnapshot) are keyed by block.timestamp,
        // not block.number — query getPriorVotes with a timestamp.
        uint _priorVotes = safetyModule.getPriorVotes(
            _user,
            block.timestamp - 1
        );
        _result = Votes(
            _priorVotes,
            safetyModule.balanceOf(_user),
            address(0)
        );
    }
}

function _checkFilterOperator(address operator) internal view virtual override {
    // Check registry code length to facilitate testing in environments without a deployed registry.
    if (
        !RevokableOperatorFiltererUpgradeableStorage.layout()._isOperatorFilterRegistryRevoked
            && address(OPERATOR_FILTER_REGISTRY).code.length > 0
    ) {
        // under normal circumstances, this function will revert rather than return false, but inheriting or
        // upgraded contracts may specify their own OperatorFilterRegistry implementations, which may behave
        // differently
        if (!OPERATOR_FILTER_REGISTRY.isOperatorAllowed(address(this), operator)) {
            revert OperatorNotAllowed(operator);
        }
    }
}

