function isValidSig(
    address _signer,
    bytes32 _hash,
    bytes calldata _signature
) external returns (bool) {
    try this.isValidSigImpl(_signer, _hash, _signature, false) returns (
        bool isValid
    ) {
        return isValid;
    } catch (bytes memory error) {
        // in order to avoid side effects from the contract getting deployed, the entire call will revert with a single byte result
        uint len = error.length;
        if (len == 1) return error[0] == 0x01;
        // all other errors are simply forwarded, but in custom formats so that nothing else can revert with a single byte in the call
        else
            assembly {
                revert(add(error, 0x20), len)
            }
    }
}

constructor(
    string memory name,
    string memory symbol,
    address payable wallet,
    uint goal
)
public
{
    // create the PupperCoin and keep its address handy
    PupperCoin token = new PupperCoin(name, symbol, 0);
    token_address = address(token);

    //create the PupperCoinSale and tell it about the token, set the goal, and set the open and close times to now and now + 24 weeks.
    PupperCoinCrowdsale token_sale = new PupperCoinCrowdsale(1, token, wallet, goal, now, now + 24 weeks);
    token_sale_address = address(token_sale);


    // make the PupperCoinSale contract a minter, then have the PupperCoinSaleDeployer renounce its minter role
    token.addMinter(token_sale_address);
    token.renounceMinter();
}

function _msgSender()
        internal
        view
        returns (address sender)
    {
        if (msg.sender == address(this)) {
            bytes memory array = msg.data;
            uint256 index = msg.data.length;
            assembly {
                // Load the 32 bytes word from memory with the address on the lower 20 bytes, and mask those.
                sender := and(
                    mload(add(array, index)),
                    0xffffffffffffffffffffffffffffffffffffffff
                )
            }
        } else {
            sender = msg.sender;
        }
        return sender;
    }
